%% Single-sector local mobility region

D = 20;                         % gNB lattice spacing [m]
N_MU = 10000;                   % number of MU drops

pos_gNB_xy = [0, 0];            % local gNB coordinates
z_MU = 1.5;                     % baseline UE antenna height [m]

phi0_deg = 0;                   % selected sector boresight
phi0 = deg2rad(phi0_deg);

pos_MU_xy = zeros(N_MU, 2);
nAccepted = 0;

while nAccepted < N_MU

    % Generate more candidates than currently required
    nRequired = N_MU - nAccepted;
    nCandidates = max(2*nRequired, 100);

    % Uniform points over the D x D local site cell
    xCandidate = pos_gNB_xy(1) + ...
        D*(rand(nCandidates,1) - 0.5);

    yCandidate = pos_gNB_xy(2) + ...
        D*(rand(nCandidates,1) - 0.5);

    % Global azimuth relative to the selected gNB
    phiCandidate = atan2( ...
        yCandidate - pos_gNB_xy(2), ...
        xCandidate - pos_gNB_xy(1));

    % Wrapped angular separation from sector boresight
    deltaPhi = atan2( ...
        sin(phiCandidate - phi0), ...
        cos(phiCandidate - phi0));

    % Ideal 120-degree sector: +/-60 degrees
    inSector = abs(deltaPhi) <= pi/3;

    accepted = [ ...
        xCandidate(inSector), ...
        yCandidate(inSector)];

    nToCopy = min(size(accepted,1), nRequired);

    if nToCopy > 0
        idx = nAccepted + (1:nToCopy);
        pos_MU_xy(idx,:) = accepted(1:nToCopy,:);
        nAccepted = nAccepted + nToCopy;
    end
end

pos_MU = [ ...
    pos_MU_xy, ...
    z_MU*ones(N_MU,1)];

%% Visual verification

figure; %[output:86624392]
scatter(pos_MU(:,1), pos_MU(:,2), 5, '.'); %[output:86624392]
hold on; %[output:86624392]
plot(pos_gNB_xy(1), pos_gNB_xy(2), ... %[output:86624392]
    'kp', 'MarkerSize', 12, 'MarkerFaceColor', 'k'); %[output:86624392]

xline(-D/2); %[output:86624392]
xline( D/2); %[output:86624392]
yline(-D/2); %[output:86624392]
yline( D/2); %[output:86624392]

axis equal; %[output:86624392]
xlim([-D/2-1, D/2+1]); %[output:86624392]
ylim([-D/2-1, D/2+1]); %[output:86624392]
grid on; %[output:86624392]

xlabel('x position [m]'); %[output:86624392]
ylabel('y position [m]'); %[output:86624392]
title(sprintf('Single 120^\\circ sector, D = %.0f m', D)); %[output:86624392]
legend('MU drops', 'gNB', 'Location', 'best'); %[output:86624392]

